#include <bits/stdc++.h>
using namespace std;

const int N=3e5+10;

struct Node{
    int lc,rc,sum;
}tr[N*21*4];

int n,m,w[N],dep[N],f[N][21];
int s[N],t[N],dis[N],lca[N];
int root[N],tot,ans[N];
vector<int> g[N];

inline int New(){
    tot++;
    tr[tot]={0,0,0};
    return tot;
}

void dfs(int x,int fa){
    dep[x]=dep[fa]+1;
    for(int y:g[x])
        if(y!=fa){
            f[y][0]=x;
            for(int i=1;f[f[y][i-1]][i-1];i++)
                f[y][i]=f[f[y][i-1]][i-1];
            dfs(y,x);
        }
}

int LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=20;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            x=f[x][i];
    if(x==y)
        return x;
    for(int i=20;i>=0;i--)
        if(f[x][i]!=f[y][i])
            x=f[x][i],y=f[y][i];
    return f[x][0];
}

void modify(int p,int l,int r,int x,int k){
    if(l==r){
        tr[p].sum+=k;
        return;
    }
    int mid=l+r>>1;
    if(x<=mid){
        if(!tr[p].lc)
            tr[p].lc=New();
        modify(tr[p].lc,l,mid,x,k);
    }else{
        if(!tr[p].rc)
            tr[p].rc=New();
        modify(tr[p].rc,mid+1,r,x,k);
    }
}

int query(int p,int l,int r,int x){
    if(!p) return 0;
    if(l==r) return tr[p].sum;

    int mid=l+r>>1;
    if(x<=mid)
        return query(tr[p].lc,l,mid,x);
    else
        return query(tr[p].rc,mid+1,r,x);
}

int Merge(int p,int q,int l,int r){
    if(!p) return q;
    if(!q) return p;
    if(l==r){
        tr[p].sum+=tr[q].sum;
        return p;
    }
    int mid=l+r>>1;
    tr[p].lc=Merge(tr[p].lc,tr[q].lc,l,mid);
    tr[p].rc=Merge(tr[p].rc,tr[q].rc,mid+1,r);
    return p;
}

void dfs2(int x,int fa,int l){
    for(int y:g[x])
        if(y!=fa){
            dfs2(y,x,l);
            Merge(root[x],root[y],l,n);
        }
    if(l==1){
        if(w[x]+dep[x]<=n)
            ans[x]+=query(root[x],1,n,w[x]+dep[x]);
    }else
        ans[x]+=query(root[x],-n,n,w[x]-dep[x]);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
        scanf("%d",&w[i]);
    dfs(1,0);
    for(int i=1;i<=m;i++){
        scanf("%d%d",&s[i],&t[i]);
        lca[i]=LCA(s[i],t[i]);
        dis[i]=dep[s[i]]+dep[t[i]]-2*dep[lca[i]];
    }
    for(int i=1;i<=n;i++)
        root[i]=New();
    for(int i=1;i<=m;i++){
        modify(root[s[i]],1,n,dep[s[i]],1);
        if(f[lca[i]][0])
            modify(root[f[lca[i]][0]],1,n,dep[s[i]],-1);
    }
    dfs2(1,0,1);

    tot=0;
    for(int i=1;i<=n;i++)
        root[i]=New();
    for(int i=1;i<=m;i++){
        modify(root[t[i]],-n,n,dis[i]-dep[t[i]],1);
        modify(root[lca[i]],-n,n,dis[i]-dep[t[i]],-1);
    }
    dfs2(1,0,-n);
    for(int i=1;i<=n;i++)
        printf("%d ",ans[i]);
    return 0;
}
